// ── Calcular Score do Lead ─────────────────────────────────────────────
const d = $input.first().json;

let score = 0;

// Prazo (25 pts)
const prazo = (d.prazo || '').toLowerCase();
if (prazo.includes('r\u00e1pido') || prazo.includes('semana')) score += 25;
else if (prazo.includes('este m\u00eas') || prazo.includes('esse m\u00eas')) score += 20;
else if (prazo.includes('3 meses') || prazo.includes('tr\u00eas')) score += 10;

// Investimento (25 pts)
const inv = (d.investimento || '').toLowerCase();
if (inv.includes('3.000') || inv.includes('3000') || inv.includes('acima')) score += 25;
else if (inv.includes('1.500') || inv.includes('1500')) score += 20;
else if (inv.includes('800') && (inv.includes('1') || inv.includes('a'))) score += 10;

// Fornecedor (20 pts)
const forn = (d.fornecedor || '').toLowerCase();
if (forn.includes('sim') || forn.includes('j\u00e1 tenho')) score += 20;
else if (forn.includes('buscando') || forn.includes('procurando')) score += 10;

// Quantidade de produtos (15 pts)
const qtd = (d.qtd_produtos || '').toLowerCase();
if (qtd.includes('50') || qtd.includes('mais de')) score += 15;
else if (qtd.includes('20') || qtd.includes('entre')) score += 10;
else score += 5;

// Plataforma (15 pts)
const plat = (d.plataforma || '').toLowerCase();
if (plat.includes('shopify')) score += 15;
else if (plat.includes('nuvemshop') || plat.includes('nuvem')) score += 10;
else score += 5;

// Classificação
let classificacao, emoji;
if (score >= 71) { classificacao = 'Lead Quente'; emoji = '\uD83D\uDD25'; }
else if (score >= 41) { classificacao = 'Lead Morno'; emoji = '\uD83C\uDF21\uFE0F'; }
else { classificacao = 'Lead Frio'; emoji = '\u2744\uFE0F'; }

// Data/hora no formato BR (fuso Belém = UTC-3)
const agora = new Date();
agora.setHours(agora.getHours() - 3);
const dataHora = agora.toISOString().replace('T', ' ').substring(0, 16);

return [{
  json: {
    data_hora: dataHora,
    nome: d.nome || '',
    instagram: d.instagram || '',
    cidade: d.cidade || '',
    nicho: d.nicho || '',
    plataforma: d.plataforma || '',
    qtd_produtos: d.qtd_produtos || '',
    fornecedor: d.fornecedor || '',
    prazo: d.prazo || '',
    investimento: d.investimento || '',
    telefone: d.telefone || '',
    score,
    classificacao,
    emoji,
    status_crm: 'Novo Lead',
    followup_1h: 'NAO',
    followup_24h: 'NAO',
    followup_3d: 'NAO',
    followup_7d: 'NAO'
  }
}];

